@SpringBootTest
@Testcontainers
class UserRepositoryIntegrationTest {

    // Static: one container shared across ALL test methods in this class
    @Container
    static MySQLContainer<?> mysql = new MySQLContainer<>("mysql:8.0")
        .withDatabaseName("testdb")
        .withUsername("test")
        .withPassword("test")
        .withReuse(true); // reuse if already running (fast CI)

    // Override Spring Boot datasource URL with the container's actual port
    @DynamicPropertySource
    static void configureProperties(DynamicPropertyRegistry registry) {
        registry.add("spring.datasource.url",      mysql::getJdbcUrl);
        registry.add("spring.datasource.username",  mysql::getUsername);
        registry.add("spring.datasource.password",  mysql::getPassword);
        registry.add("spring.jpa.hibernate.ddl-auto", () -> "create-drop");
    }

    @Autowired UserRepository userRepo;

    @Test
    @Transactional  // rolls back after each test — clean state
    void savesAndFindsUser() {
        User user = new User();
        user.setEmail("alice@test.com");
        user.setName("Alice");
        userRepo.save(user);

        Optional<User> found = userRepo.findByEmail("alice@test.com");
        assertThat(found).isPresent();
        assertThat(found.get().getName()).isEqualTo("Alice");
    }

    @Test
    @Transactional
    void uniqueEmailConstraint() {
        User u1 = new User(); u1.setEmail("bob@test.com"); u1.setName("Bob");
        User u2 = new User(); u2.setEmail("bob@test.com"); u2.setName("Bob2");
        userRepo.save(u1);

        // This catches the REAL MySQL unique constraint violation
        // H2 might behave differently
        assertThatThrownBy(() -> {
            userRepo.save(u2);
            userRepo.flush(); // force SQL execution
        }).isInstanceOf(DataIntegrityViolationException.class);
    }
}

// ── Kafka Integration Test ────────────────────────────────────
@SpringBootTest
@Testcontainers
class OrderEventProducerTest {

    @Container
    static KafkaContainer kafka = new KafkaContainer(
        DockerImageName.parse("confluentinc/cp-kafka:7.4.0")
    );

    @DynamicPropertySource
    static void configure(DynamicPropertyRegistry registry) {
        registry.add("spring.kafka.bootstrap-servers", kafka::getBootstrapServers);
    }

    @Autowired OrderEventProducer producer;

    @Test
    void publishesOrderCreatedEvent() throws Exception {
        producer.publishOrderCreated("order-123", "customer-456");

        // Consume and verify with KafkaConsumer
        Map<String, Object> props = new HashMap<>();
        props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, kafka.getBootstrapServers());
        props.put(ConsumerConfig.GROUP_ID_CONFIG, "test-group");
        props.put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG, "earliest");
        props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);

        try (KafkaConsumer<String, String> consumer = new KafkaConsumer<>(props)) {
            consumer.subscribe(List.of("orders"));
            ConsumerRecords<String, String> records = consumer.poll(Duration.ofSeconds(5));
            assertThat(records.count()).isEqualTo(1);
            assertThat(records.iterator().next().value()).contains("order-123");
        }
    }
}

