public class Q1 {
    static final List<String> REAL_KEYWORDS = List.of(
        "constraint", "migration", "real sql", "real kafka", "real redis",
        "transaction isolation", "dialect", "schema"
    );
    static final List<String> MOCK_KEYWORDS = List.of("mock", "stub", "mocked", "in-memory");

    static String classify(String desc) {
        String d = desc.toLowerCase();
        if (REAL_KEYWORDS.stream().anyMatch(d::contains)) return "INTEGRATION_REAL";
        if (MOCK_KEYWORDS.stream().anyMatch(d::contains)) return "INTEGRATION_MOCK";
        return "UNIT";
    }

    public static void main(String[] args) {
