import java.util.*;

public class Q2 {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt(), m = sc.nextInt(); sc.nextLine();
        List<String> names = new ArrayList<>();
        for (int i = 0; i < n; i++) names.add(sc.nextLine().trim());
        Map<String, Integer> idx = new HashMap<>();
        for (int i = 0; i < n; i++) idx.put(names.get(i), i);
        int[] inDeg = new int[n];
        List<List<Integer>> adj = new ArrayList<>();
        for (int i = 0; i < n; i++) adj.add(new ArrayList<>());
        for (int i = 0; i < m; i++) {
            String[] p = sc.nextLine().trim().split(" ");
            int u = idx.get(p[0]), v = idx.get(p[1]);
            adj.get(u).add(v);
            inDeg[v]++;
        }
        Queue<Integer> queue = new LinkedList<>();
        for (int i = 0; i < n; i++) if (inDeg[i] == 0) queue.add(i);
        List<String> result = new ArrayList<>();
        while (!queue.isEmpty()) {
            int u = queue.poll();
            result.add(names.get(u));
            for (int v : adj.get(u)) if (--inDeg[v] == 0) queue.add(v);
        }
        System.out.println(String.join(" ", result));
    }
}

