import java.util.*;

public class Q3 {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt(); sc.nextLine();
        Map<String, String> lastWriter = new HashMap<>();
        List<String> violations = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            String line = sc.nextLine().trim();
            String testName = line.split(":")[0].replace("TEST ", "").trim();
            String rest = line.substring(line.indexOf(':') + 1).trim();
            String[] tokens = rest.split(" ");
            String mode = null;
            for (String token : tokens) {
                if (token.equals("WRITE") || token.equals("READ")) { mode = token; continue; }
                if (token.contains("=") && mode != null) {
                    String key = token.split("=")[0];
                    if (mode.equals("WRITE")) {
                        lastWriter.put(key, testName);
                    } else if (mode.equals("READ")) {
                        String writer = lastWriter.get(key);
                        if (writer != null && !writer.equals(testName))
                            violations.add("VIOLATION: " + testName + " reads " + key + " written by " + writer);
                    }
                }
            }
        }
        if (violations.isEmpty()) System.out.println("OK");
        else violations.forEach(System.out::println);
    }
}
